type S3Query {
  s3Files(prefix: String = ""): S3FileList!
  s3FileData(fileKey: String!, limit: Int = null, offset: Int = null): S3FileData!
  s3FileInfo(fileKey: String!): S3FileInfo!
  s3FileDownloadUrl(fileKey: String!, expiresIn: Int = null): S3DownloadUrlResponse!
  s3FileSchema(fileKey: String!): [FileSchemaColumn!]!
  s3FileStats(fileKey: String!): S3FileStats!
  s3BucketMetadata: JSON!
}

type S3Mutation {
  initiateCsvUpload(input: InitiateCsvUploadInput!): InitiateUploadResponse!
  completeCsvUpload(input: CompleteUploadInput!): CompleteUploadResponse!
  deleteFile(fileKey: String!): Boolean!
}

input InitiateCsvUploadInput {
  filename: String!
  fileSize: BigInt!
}

input CompleteUploadInput {
  uploadId: String!
}

code_blocks.value:
{
  "query": "query ($prefix: String) { s3 { s3Files(prefix: $prefix) { total files { key filename size } } } }",
  "variables": { "prefix": "" }
}

{
  "query": "query ($fileKey: String!, $expiresIn: Int) { s3 { s3FileDownloadUrl(fileKey: $fileKey, expiresIn: $expiresIn) { downloadUrl expiresIn } } }",
  "variables": { "fileKey": "upload/20260210_120000_contacts.csv", "expiresIn": 3600 }
}

type S3FileList {
  files: [S3FileInfo!]!
  total: Int!
  bucketDisplayName: String
}

type S3DownloadUrlResponse {
  downloadUrl: String!
  expiresIn: Int!
}

type S3FileDataRow {
  data: JSON!
}

query ListS3Files($prefix: String) {
  s3 {
    s3Files(prefix: $prefix) {
      files {
        key
        filename
        size
        lastModified
        contentType
      }
      total
      bucketDisplayName
    }
  }
}

{
  "prefix": "upload/"
}

{
  "data": {
    "s3": {
      "s3Files": {
        "files": [
          {
            "key": "exports/exp_123456.csv",
            "filename": "exp_123456.csv",
            "size": 524288,
            "lastModified": "2024-01-15T10:30:00Z",
            "contentType": "text/csv"
          }
        ],
        "total": 1
      }
    }
  }
}

query GetS3FileData($fileKey: String!, $limit: Int!, $offset: Int) {
  s3 {
    s3FileData(fileKey: $fileKey, limit: $limit, offset: $offset) {
      fileKey
      rows {
        data
      }
      limit
      offset
      totalRows
    }
  }
}

{
  "fileKey": "upload/exp_123456.csv",
  "limit": 100,
  "offset": 0
}

{
  "data": {
    "s3": {
      "s3FileData": {
        "fileKey": "exports/exp_123456.csv",
        "rows": [
          {
            "data": {
              "uuid": "123e4567-e89b-12d3-a456-426614174000",
              "firstName": "John",
              "lastName": "Doe",
              "email": "john.doe@example.com"
            }
          }
        ],
        "limit": 100,
        "offset": 0,
        "totalRows": 150
      }
    }
  }
}

query GetS3FileDownloadUrl($fileKey: String!, $expiresIn: Int) {
  s3 {
    s3FileDownloadUrl(fileKey: $fileKey, expiresIn: $expiresIn) {
      downloadUrl
      expiresIn
    }
  }
}

